Here's a modern MSTest 3.x test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NonSuccessStatus_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange — handler that delays forever, simulating a slow server
        var handler = new FakeHandler(delay: Timeout.InfiniteTimeSpan);
        var fetcher = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_TimeoutViaTestContext_IsCancelledCooperatively()
    {
        // TestContext.CancellationToken fires when [Timeout] elapses,
        // verifying FetchAsync honors cooperative cancellation.
        var handler = new FakeHandler(delay: Timeout.InfiniteTimeSpan);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // If FetchAsync ignores the token this test will timeout and fail.
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    /// <summary>Minimal handler that returns a canned response or delays.</summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage? _response;
        private readonly TimeSpan _delay;

        public FakeHandler(HttpResponseMessage response) => _response = response;

        public FakeHandler(TimeSpan delay) => _delay = delay;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken);
            }

            return _response ?? new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `sealed` class | Performance + design clarity |
| Constructor-injected `TestContext` | Enables `readonly`, satisfies nullability |
| `[Timeout]` + `TestContext.CancellationToken` | Cooperative timeout — test fails cleanly instead of hanging |
| `Assert.ThrowsExactlyAsync<T>` | Modern exception testing (replaces `[ExpectedException]`) |
| `FakeHandler` | Avoids real HTTP; controls responses and simulates delays |
| Explicit `CancellationTokenSource` | Tests that `FetchAsync` honors caller-provided cancellation |

The last test (`TimeoutViaTestContext`) is particularly important — it proves that if `FetchAsync` ever stops forwarding the cancellation token, the test will hang and fail via `[Timeout]`, catching the regression.
